"use client";

import { Sidebar as SidebarRoot, type SidebarProps } from "./sidebar";
import { SidebarProvider, type SidebarProviderProps, SIDEBAR_STATE_COOKIE } from "./sidebar-provider";
import { SidebarTrigger, type SidebarTriggerProps } from "./sidebar-trigger";
import { SidebarHeader, type SidebarHeaderProps } from "./sidebar-header";
import { SidebarContent, type SidebarContentProps } from "./sidebar-content";
import { SidebarSection, type SidebarSectionProps } from "./sidebar-section";
import { SidebarSectionContent, type SidebarSectionContentProps } from "./sidebar-section-content";
import {
  SidebarSectionTitle,
  type SidebarSectionTitleProps,
  type SidebarSectionTitleHeadingLevel,
} from "./sidebar-section-title";
import {
  SidebarItem,
  type SidebarItemProps,
  type SidebarItemAsButtonProps,
  type SidebarItemAsAnchorProps,
  type SidebarItemRenderProps,
} from "./sidebar-item";
import { SidebarItemLabel, type SidebarItemLabelProps } from "./sidebar-item-label";
import { SidebarItemBadge, type SidebarItemBadgeProps } from "./sidebar-item-badge";
import { SidebarFooter, type SidebarFooterProps } from "./sidebar-footer";
import type { SidebarVariant } from "@/lib/sidebar-variants";
import type { SidebarIntent } from "@/lib/sidebar-intent";
import type { SidebarState } from "./sidebar-context";

const Sidebar = Object.assign(SidebarRoot, {
  Provider: SidebarProvider,
  Trigger: SidebarTrigger,
  Header: SidebarHeader,
  Content: SidebarContent,
  Section: SidebarSection,
  SectionTitle: SidebarSectionTitle,
  SectionContent: SidebarSectionContent,
  Item: SidebarItem,
  ItemLabel: SidebarItemLabel,
  ItemBadge: SidebarItemBadge,
  Footer: SidebarFooter,
});

export { Sidebar, type SidebarProps };
export { SidebarProvider, type SidebarProviderProps, SIDEBAR_STATE_COOKIE };
export { SidebarTrigger, type SidebarTriggerProps };
export { SidebarHeader, type SidebarHeaderProps };
export { SidebarContent, type SidebarContentProps };
export { SidebarSection, type SidebarSectionProps };
export { SidebarSectionContent, type SidebarSectionContentProps };
export { SidebarSectionTitle, type SidebarSectionTitleProps, type SidebarSectionTitleHeadingLevel };
export {
  SidebarItem,
  type SidebarItemProps,
  type SidebarItemAsButtonProps,
  type SidebarItemAsAnchorProps,
  type SidebarItemRenderProps,
};
export { SidebarItemLabel, type SidebarItemLabelProps };
export { SidebarItemBadge, type SidebarItemBadgeProps };
export { SidebarFooter, type SidebarFooterProps };
export { useSidebar } from "./sidebar-context";
export type { SidebarVariant, SidebarIntent, SidebarState };

"use client";

import { useMemo, type HTMLAttributes, type ReactNode, type Ref } from "react";
import { cn } from "@/lib/utils";
import { sidebarContainerVariants, type SidebarVariant } from "@/lib/sidebar-variants";
import { Dialog, DialogContent } from "../dialog";
import {
  SidebarChromeContext,
  useOptionalSidebar,
  useSidebar,
} from "./sidebar-context";
import { SidebarProvider } from "./sidebar-provider";

export interface SidebarProps extends HTMLAttributes<HTMLElement> {
  ref?: Ref<HTMLElement>;
  /**
   * Visual variant. Active-marker treatment changes per variant; row metrics
   * stay identical so glyph slots line up across variants.
   *   - `caret`    — `▸` glyph prefix; active = `font-semibold`, no row bg.
   *   - `inverted` — TUI cursor line; active = full-bleed `bg-foreground`.
   *   - `bar`      — 1px `border-l` on active; zero radius, no fill.
   *   - `bracket`  — `[*]` (active) / `[ ]` (inactive) glyph prefix.
   *   - `block`    — soft `bg-foreground/8` fill on active.
   */
  variant?: SidebarVariant;
  /**
   * Opt-in: render a `data-intent` dot before each item's label and derive
   * intent from the item `value` via the built-in dictionary when not
   * explicitly set. Color is decoration only (WCAG 1.4.1) — pair with text
   * cues such as labels or badges.
   */
  autoTone?: boolean;
  children: ReactNode;
}

function SidebarNav({
  ref,
  variant,
  autoTone,
  className,
  "aria-label": ariaLabel,
  children,
  ...rest
}: HTMLAttributes<HTMLElement> & {
  ref?: Ref<HTMLElement>;
  variant: SidebarVariant;
  autoTone: boolean;
}) {
  const { state } = useSidebar();
  return (
    <nav
      ref={ref}
      aria-label={ariaLabel ?? "Primary"}
      data-slot="sidebar"
      data-variant={variant}
      data-state={state}
      data-auto-tone={autoTone || undefined}
      {...rest}
      className={cn(sidebarContainerVariants({ state }), className)}
    >
      {children}
    </nav>
  );
}

/**
 * Reads context state to decide whether to render the inline nav or the
 * mobile sheet wrapper. Kept separate so the host (Provider) can render
 * `aria-live` announcers + mobile sheet without re-entering the Sidebar
 * branch logic.
 */
function SidebarShell({
  ref,
  variant,
  autoTone,
  className,
  children,
  "aria-label": ariaLabel,
  ...rest
}: {
  ref?: Ref<HTMLElement>;
  variant: SidebarVariant;
  autoTone: boolean;
  className?: string;
  children: ReactNode;
} & HTMLAttributes<HTMLElement>) {
  const { state, isMobile, onStateChange } = useSidebar();
  const open = state !== "hidden";

  if (isMobile) {
    // Mobile: render the same chrome inside a Dialog sheet. Width is fixed
    // by the sheet wrapper (86vw / max 320px) and the inner nav fills it.
    return (
      <Dialog open={open} onOpenChange={(next) => onStateChange(next ? "open" : "hidden")}>
        <DialogContent
          aria-label={ariaLabel ?? "Primary navigation"}
          className="!max-w-[min(86vw,320px)] !h-[100dvh] !max-h-[100dvh] !m-0 !border-r border-border !rounded-none p-0 pb-[env(safe-area-inset-bottom)]"
          frame="none"
        >
          <SidebarNav
            ref={ref}
            variant={variant}
            autoTone={autoTone}
            className={cn("h-full w-full", className)}
            data-mobile="true"
            aria-label={ariaLabel}
            {...rest}
          >
            {children}
          </SidebarNav>
        </DialogContent>
      </Dialog>
    );
  }

  return (
    <SidebarNav
      ref={ref}
      variant={variant}
      autoTone={autoTone}
      className={className}
      aria-label={ariaLabel}
      {...rest}
    >
      {children}
    </SidebarNav>
  );
}

/**
 * `Sidebar` is a "Sidebar inside provider" convenience: passing it without an
 * outer `<SidebarProvider>` instantiates one automatically. When nested inside
 * an existing provider (e.g. for an app that mounts the same provider once at
 * the root and renders the sidebar in multiple slots), it reuses that context.
 *
 * Mobile breakpoint and hotkey config live on `<SidebarProvider>`; this
 * convenience signature does not surface them — use `<SidebarProvider>`
 * directly when you need them.
 */
export function Sidebar({
  ref,
  variant,
  autoTone = false,
  children,
  className,
  ...rest
}: SidebarProps) {
  const existingContext = useOptionalSidebar();
  const resolvedVariant = variant ?? "caret";
  const chromeValue = useMemo(
    () => ({ variant: resolvedVariant, autoTone }),
    [resolvedVariant, autoTone],
  );

  const chrome = (
    <SidebarChromeContext value={chromeValue}>
      <SidebarShell
        ref={ref}
        variant={resolvedVariant}
        autoTone={autoTone}
        className={className}
        {...rest}
      >
        {children}
      </SidebarShell>
    </SidebarChromeContext>
  );

  if (existingContext) return chrome;
  return <SidebarProvider>{chrome}</SidebarProvider>;
}

"use client";

import { createContext, useContext } from "react";
import type { SidebarVariant } from "@/lib/sidebar-variants";

export type SidebarState = "open" | "rail" | "hidden";

/**
 * State context owns runtime behaviour (open/rail/hidden, mobile mode, hotkey
 * wiring). Kept separate from the chrome context so a visual-only re-render
 * doesn't churn state consumers.
 */
export interface SidebarContextValue {
  state: SidebarState;
  contentId: string;
  isMobile: boolean;
  onStateChange: (state: SidebarState) => void;
  toggleSidebar: () => void;
  toggleHidden: () => void;
}

export const SidebarContext = createContext<SidebarContextValue | undefined>(undefined);

export function useSidebar() {
  const context = useContext(SidebarContext);
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider or Sidebar");
  }
  return context;
}

export function useOptionalSidebar() {
  return useContext(SidebarContext);
}

/**
 * Chrome context owns visual style (variant signature, autoTone opt-in). Lives
 * on the Sidebar root so the same Provider can host different chrome flavours
 * (e.g. dual sidebars in one app shell).
 */
export interface SidebarChromeContextValue {
  variant: SidebarVariant;
  autoTone: boolean;
}

export const SidebarChromeContext = createContext<SidebarChromeContextValue>({
  variant: "caret",
  autoTone: false,
});

export function useSidebarChrome() {
  return useContext(SidebarChromeContext);
}

"use client";

import { useCallback, useEffect, useId, useMemo, type ReactNode } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useIsMobile } from "@/hooks/use-is-mobile";
import { SidebarContext, type SidebarState } from "./sidebar-context";

export interface SidebarProviderProps {
  state?: SidebarState;
  defaultState?: SidebarState;
  onStateChange?: (state: SidebarState) => void;
  /**
   * Viewport width (in pixels) below which the sidebar collapses into a
   * mobile sheet. Default `1024` (Tailwind `lg`).
   */
  breakpoint?: number;
  /**
   * Keyboard shortcut character (case-insensitive). `Cmd/Ctrl+<key>` cycles
   * `open` ↔ `rail`; `Shift+Cmd/Ctrl+<key>` toggles `hidden`. Pass `null` to
   * disable the hotkey. Default `"b"` (VS Code convention).
   */
  shortcutKey?: string | null;
  children: ReactNode;
}

/**
 * Cookie name for persistence — documented for SSR consumers.
 *
 * The provider intentionally does NOT read or write the cookie. SSR
 * frameworks (TanStack Start, Next.js App Router) should parse the cookie
 * in their route loader and pass the value as `defaultState`, then mirror
 * `onStateChange` writes back via `document.cookie` (`SameSite=Lax`, 1y).
 * Doing the read inside the provider would either cause a hydration
 * mismatch (server snapshot != cookie value) or force every consumer to
 * deal with hidden environment assumptions.
 */
export const SIDEBAR_STATE_COOKIE = "dg_sidebar_state";

/**
 * Minimal editable-target guard for the global Cmd/Ctrl+B hotkey. A more
 * thorough version lives in `@diffgazer/keys` as `isEditableElement` (handles
 * input types, disabled/readOnly, etc.), but the sidebar primitive is meant to
 * install cleanly in copy mode without pulling that full keys/focus surface in
 * just for the hotkey suppression. The hotkey only fires for plain
 * INPUT/TEXTAREA/SELECT/contentEditable targets, which is the realistic typing
 * surface a user wouldn't want to clobber with a sidebar toggle.
 */
function isEditableTarget(target: EventTarget | null): boolean {
  if (!(target instanceof HTMLElement)) return false;
  if (target.isContentEditable) return true;
  const tag = target.tagName;
  return tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT";
}

export function SidebarProvider({
  state: controlledState,
  defaultState = "open",
  onStateChange,
  breakpoint = 1024,
  shortcutKey = "b",
  children,
}: SidebarProviderProps) {
  const sidebarId = useId();
  const [state, setState] = useControllableState<SidebarState>({
    value: controlledState,
    defaultValue: defaultState,
    onChange: onStateChange,
  });
  const isMobile = useIsMobile(breakpoint);

  const toggleSidebar = useCallback(() => {
    setState(prev => (prev === "open" ? "rail" : "open"));
  }, [setState]);

  const toggleHidden = useCallback(() => {
    setState(prev => (prev === "hidden" ? "open" : "hidden"));
  }, [setState]);

  useEffect(() => {
    if (!shortcutKey) return;
    const normalizedKey = shortcutKey.toLowerCase();
    const handler = (event: KeyboardEvent) => {
      if (event.key.toLowerCase() !== normalizedKey) return;
      if (!(event.metaKey || event.ctrlKey)) return;
      if (isEditableTarget(event.target)) return;
      event.preventDefault();
      if (event.shiftKey) {
        toggleHidden();
      } else {
        toggleSidebar();
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [shortcutKey, toggleSidebar, toggleHidden]);

  const contextValue = useMemo(
    () => ({
      state,
      contentId: `${sidebarId}-content`,
      isMobile,
      onStateChange: setState,
      toggleSidebar,
      toggleHidden,
    }),
    [state, isMobile, setState, sidebarId, toggleSidebar, toggleHidden],
  );

  return (
    <SidebarContext value={contextValue}>
      {children}
    </SidebarContext>
  );
}

"use client";

import type { ButtonHTMLAttributes, Ref } from "react";
import { cn } from "@/lib/utils";
import { useSidebar } from "./sidebar-context";

export interface SidebarTriggerProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  ref?: Ref<HTMLButtonElement>;
}

/**
 * Toggle button for the sidebar's open/rail (desktop) or open/hidden (mobile)
 * state. The default glyph is the terminal-style `[≡]` (collapsed) → `[×]`
 * (open) pair — consumers can replace it via `children`.
 */
export function SidebarTrigger({
  ref,
  className,
  onClick,
  children,
  "aria-label": ariaLabel,
  ...props
}: SidebarTriggerProps) {
  const { state, isMobile, contentId, toggleSidebar, onStateChange } = useSidebar();
  const isOpen = isMobile ? state !== "hidden" : state === "open";
  const visualState: "open" | "collapsed" = isOpen ? "open" : "collapsed";
  const labelDefault = isMobile
    ? (isOpen ? "Close navigation" : "Open navigation")
    : (isOpen ? "Collapse sidebar" : "Expand sidebar");

  const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
    onClick?.(event);
    if (event.defaultPrevented) return;
    if (isMobile) {
      onStateChange(isOpen ? "hidden" : "open");
    } else {
      toggleSidebar();
    }
  };

  return (
    <button
      {...props}
      ref={ref}
      type="button"
      aria-controls={props["aria-controls"] ?? contentId}
      aria-expanded={isOpen}
      aria-label={ariaLabel ?? labelDefault}
      data-state={visualState}
      className={cn("inline-flex items-center justify-center font-mono", className)}
      onClick={handleClick}
    >
      {children ?? (
        <span aria-hidden="true">{isOpen ? "[×]" : "[≡]"}</span>
      )}
    </button>
  );
}

"use client";

import type { HTMLAttributes, Ref } from "react";
import { cn } from "@/lib/utils";

export interface SidebarHeaderProps extends HTMLAttributes<HTMLDivElement> {
  ref?: Ref<HTMLDivElement>;
}

export function SidebarHeader({ ref, children, className, ...props }: SidebarHeaderProps) {
  return (
    <div ref={ref} className={cn("px-4 py-3 border-b border-border shrink-0", className)} {...props}>
      {children}
    </div>
  );
}

"use client";

import { useRef, type HTMLAttributes, type KeyboardEvent, type Ref } from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { cn } from "@/lib/utils";
import { composeRefs } from "@/lib/compose-refs";
import { useSidebar } from "./sidebar-context";

export interface SidebarContentProps extends HTMLAttributes<HTMLDivElement> {
  ref?: Ref<HTMLDivElement>;
}

/**
 * Scroll body for the sidebar. Hides itself when `state === "hidden"` so its
 * descendants drop out of the tab order; rail state keeps it mounted (icons
 * only) so collapsing does not lose focus or scroll position.
 */
export function SidebarContent({ ref, children, className, onKeyDown, ...props }: SidebarContentProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const { state, contentId } = useSidebar();
  const hidden = state === "hidden";
  const ariaHidden = hidden ? true : props["aria-hidden"];

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "button",
    orientation: "vertical",
    wrap: true,
    moveFocus: true,
    scopeToContainer: true,
  });

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    onKeyDown?.(e);
    if (!e.defaultPrevented) navKeyDown(e);
  };

  return (
    <div
      {...props}
      ref={composeRefs(containerRef, ref)}
      id={props.id ?? contentId}
      aria-hidden={ariaHidden}
      inert={hidden ? true : undefined}
      hidden={hidden || props.hidden || undefined}
      data-state={state}
      className={cn(
        "flex-1 overflow-y-auto p-4",
        // Rail mode: zero horizontal padding so items center inside the 48px
        // rail. Vertical padding stays so the first/last items breathe.
        "group-data-[state=rail]/sidebar:px-0",
        className,
      )}
      onKeyDown={handleKeyDown}
    >
      {children}
    </div>
  );
}

"use client";

import { Children, isValidElement, useId, useMemo, type HTMLAttributes, type ReactNode, type Ref } from "react";
import { cn } from "@/lib/utils";
import { useControllableState } from "@/hooks/use-controllable-state";
import { SidebarSectionContext } from "./sidebar-section-context";
import { SidebarSectionTitle } from "./sidebar-section-title";

export interface SidebarSectionProps extends HTMLAttributes<HTMLDivElement> {
  ref?: Ref<HTMLDivElement>;
  collapsible?: boolean;
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  defaultOpen?: boolean;
}

/**
 * Group container. When `collapsible`, follows the ARIA disclosure pattern —
 * the `<SidebarSectionTitle>` renders an `<hN><button aria-expanded …>…</button></hN>`
 * that controls a sibling `<SidebarSectionContent>` panel (id wired via
 * context). Items NOT wrapped in `<SidebarSectionContent>` render unhidden;
 * this keeps non-collapsible sections trivial to compose.
 */
export function SidebarSection({
  ref,
  collapsible = false,
  open: controlledOpen,
  onOpenChange,
  defaultOpen = true,
  className,
  children,
  "aria-labelledby": ariaLabelledBy,
  ...rest
}: SidebarSectionProps) {
  const titleId = useId();
  const panelId = useId();
  const labelSourceId = ariaLabelledBy ?? (containsSidebarSectionTitleElement(children) ? titleId : undefined);

  const [isOpen, setIsOpen] = useControllableState<boolean>({
    value: controlledOpen,
    defaultValue: defaultOpen,
    onChange: onOpenChange,
  });

  const contextValue = useMemo(
    () => ({
      collapsible,
      open: isOpen,
      onToggle: () => setIsOpen(prev => !prev),
      titleId,
      panelId,
    }),
    [collapsible, isOpen, setIsOpen, titleId, panelId],
  );

  return (
    <SidebarSectionContext value={contextValue}>
      <div
        {...rest}
        ref={ref}
        role="group"
        aria-labelledby={labelSourceId}
        data-state={isOpen ? "open" : "closed"}
        className={cn("mb-4", className)}
      >
        {children}
      </div>
    </SidebarSectionContext>
  );
}

function containsSidebarSectionTitleElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === SidebarSectionTitle) return true;
    return containsSidebarSectionTitleElement(child.props.children);
  });
}

"use client";

import { createContext, useContext } from "react";

export interface SidebarSectionContextValue {
  collapsible: boolean;
  open: boolean;
  onToggle: () => void;
  titleId: string;
  panelId: string;
}

export const SidebarSectionContext = createContext<SidebarSectionContextValue | undefined>(undefined);

export function useSidebarSectionContext() {
  const context = useContext(SidebarSectionContext);
  if (!context) {
    throw new Error("SidebarSection compound components must be used within a SidebarSection");
  }
  return context;
}

export function useOptionalSidebarSectionContext() {
  return useContext(SidebarSectionContext);
}

"use client";

import { createElement, type HTMLAttributes, type MouseEvent, type ReactNode, type Ref } from "react";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import { useSidebarSectionContext } from "./sidebar-section-context";

export type SidebarSectionTitleHeadingLevel = "h1" | "h2" | "h3" | "h4" | "h5" | "h6";

export interface SidebarSectionTitleProps extends HTMLAttributes<HTMLElement> {
  ref?: Ref<HTMLElement>;
  handle?: ReactNode | null;
  /**
   * Heading level to render. Default `"h3"` matches the typical sidebar
   * placement under a page `<h1>` and a `<h2>` section header — the level
   * that keeps screen-reader heading-rotor navigation predictable.
   */
  headingLevel?: SidebarSectionTitleHeadingLevel;
}

// Hidden in rail mode: section titles read as truncated text inside a 48px
// rail. The section divider (top border between sibling sections) becomes the
// visual group separator in rail.
const HEADING_CLASS_NAME =
  "px-2 py-2 text-muted-foreground text-xs font-mono font-normal lowercase tracking-normal m-0 group-data-[state=rail]/sidebar:hidden";

/**
 * Renders the section title as a real heading (`<h3>` by default) so screen
 * readers expose it via the heading-rotor. Collapsible sections follow the
 * ARIA disclosure pattern — `<hN><button aria-expanded aria-controls=…>…</button></hN>` —
 * keeping the heading semantic and the toggle interactive without nesting
 * roles incorrectly. `aria-controls` targets the sibling
 * `<SidebarSectionContent>` panel id, exposed via section context.
 */
export function SidebarSectionTitle({
  ref,
  children,
  className,
  onClick,
  handle,
  headingLevel = "h3",
  ...rest
}: SidebarSectionTitleProps) {
  const { collapsible, open, onToggle, titleId, panelId } = useSidebarSectionContext();
  const resolvedHandle = handle === undefined ? <Chevron open={open} size="sm" /> : handle;
  const isInteractive = collapsible || !!onClick;

  if (isInteractive) {
    const handleClick = (e: MouseEvent<HTMLButtonElement>) => {
      onClick?.(e);
      if (collapsible && !e.defaultPrevented) onToggle();
    };

    return createElement(
      headingLevel,
      { ref, id: titleId, className: cn(HEADING_CLASS_NAME, className) },
      <button
        {...(rest as HTMLAttributes<HTMLButtonElement>)}
        type="button"
        className={cn(
          "text-left w-full appearance-none cursor-pointer select-none bg-transparent border-0 p-0 m-0",
          "font-[inherit] text-[inherit]",
          // Intentional asymmetry: only the collapsible branch needs the row
          // layout, because only that branch renders the chevron handle next
          // to the label. A non-collapsible `onClick` title is just label
          // text with a click handler and inherits the heading's block layout.
          collapsible && "flex items-center gap-1",
        )}
        onClick={handleClick}
        aria-expanded={collapsible ? open : undefined}
        aria-controls={collapsible ? panelId : undefined}
      >
        {collapsible && resolvedHandle}
        {children}
      </button>,
    );
  }

  return createElement(
    headingLevel,
    { ...rest, ref, id: titleId, className: cn(HEADING_CLASS_NAME, className) },
    children,
  );
}

"use client";

import type { HTMLAttributes, Ref } from "react";
import { cn } from "@/lib/utils";
import { useSidebarSectionContext } from "./sidebar-section-context";

export interface SidebarSectionContentProps extends HTMLAttributes<HTMLDivElement> {
  ref?: Ref<HTMLDivElement>;
}

/**
 * Panel slot for collapsible sections. Wraps the items so the section title's
 * disclosure button can reference a single `aria-controls` target.
 *
 * Animation: the element stays in the DOM at all times so the `grid-template-rows`
 * 0fr → 1fr transition (defined in `shared/sidebar.css`) can tween height; the
 * inner wrapper carries `min-height: 0; overflow: hidden` so the grid can
 * squeeze the row to zero. When closed, `inert` removes descendants from the
 * tab order and `aria-hidden` removes them from the accessibility tree. For
 * non-collapsible sections this is a no-op wrapper and can be omitted.
 */
export function SidebarSectionContent({
  ref,
  className,
  children,
  ...rest
}: SidebarSectionContentProps) {
  const { open, panelId, collapsible } = useSidebarSectionContext();
  const isClosed = collapsible && !open;

  return (
    <div
      {...rest}
      ref={ref}
      id={panelId}
      data-slot="sidebar-section-content"
      data-state={open ? "open" : "closed"}
      aria-hidden={isClosed || undefined}
      inert={isClosed || undefined}
    >
      <div
        data-slot="sidebar-section-content-inner"
        className={cn("flex flex-col", className)}
      >
        {children}
      </div>
    </div>
  );
}

"use client";

import { useId } from "react";
import type {
  AnchorHTMLAttributes,
  ButtonHTMLAttributes,
  MouseEventHandler,
  MouseEvent as ReactMouseEvent,
  ReactNode,
  Ref,
} from "react";

import { resolveSidebarIntent, type SidebarIntent } from "@/lib/sidebar-intent";
import { sidebarItemVariants, type SidebarVariant } from "@/lib/sidebar-variants";
import { cn } from "@/lib/utils";
import { useSidebarChrome } from "./sidebar-context";

export interface SidebarItemRenderProps {
  ref?: Ref<HTMLElement>;
  className: string;
  disabled?: boolean;
  onClick?: MouseEventHandler<HTMLElement>;
  "aria-current"?: "page";
  "aria-disabled"?: boolean;
  "data-active"?: "true";
  "data-intent"?: SidebarIntent;
  "data-diffgazer-navigation-item"?: "button";
  "data-value"?: string;
  "data-disabled"?: "";
  tabIndex?: number;
}

interface SidebarItemSharedProps {
  active?: boolean;
  value?: string;
  /**
   * Optional intent for `data-intent`. When `autoTone` is enabled on the
   * parent `<Sidebar>` and `intent` is omitted, the intent is inferred from
   * `value` via the built-in dictionary. Color is decoration only
   * (WCAG 1.4.1) — provide a text/glyph cue alongside (label or badge).
   */
  intent?: SidebarIntent;
  /**
   * Either a renderable node (icon, label, badge) or a render-prop callback
   * that receives the wired-up props for composing a custom element such as a
   * framework `<Link>`.
   *
   * Render-prop consumers compose their own decoration — the caret/bracket
   * variant glyph and the `autoTone` intent dot are NOT injected automatically
   * through the render prop. Use the built-in element rendering (`as="a"` or
   * `as="button"`) to get the glyph and dot for free, or replicate them in
   * your render callback.
   */
  children: ReactNode | ((props: SidebarItemRenderProps) => ReactNode);
  className?: string;
  disabled?: boolean;
}

export interface SidebarItemAsAnchorProps
  extends Omit<AnchorHTMLAttributes<HTMLAnchorElement>, "children" | "value">,
    SidebarItemSharedProps {
  as?: "a";
  ref?: Ref<HTMLAnchorElement>;
}

export interface SidebarItemAsButtonProps
  extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, "children" | "disabled" | "value">,
    SidebarItemSharedProps {
  as: "button";
  ref?: Ref<HTMLButtonElement>;
}

export type SidebarItemProps = SidebarItemAsAnchorProps | SidebarItemAsButtonProps;

const INTENT_DOT_CLASSES: Record<SidebarIntent, string> = {
  neutral: "bg-muted-foreground",
  info: "bg-[var(--info,oklch(0.62_0.20_240))]",
  success: "bg-[var(--success,oklch(0.62_0.20_145))]",
  warning: "bg-[var(--warning,oklch(0.62_0.20_75))]",
  danger: "bg-[var(--danger,oklch(0.62_0.20_25))]",
  accent: "bg-[var(--accent,oklch(0.62_0.20_295))]",
};

/**
 * Glyph prefix for `caret` and `bracket` variants. Rendered as `aria-hidden`
 * so screen readers skip it — the label text remains the sole accessible
 * name. Brackets stay visible for inactive rows per spec, with monospaced
 * tabular alignment ensuring no width-shift on selection. Hidden in rail mode
 * so items collapse to icon-only rows centered in the 48px rail.
 */
function VariantGlyph({ variant, active }: { variant: SidebarVariant; active: boolean }) {
  if (variant === "caret") {
    return (
      <span
        aria-hidden="true"
        className="inline-block w-[1ch] shrink-0 text-muted-foreground tabular-nums group-data-[state=rail]/sidebar:hidden"
      >
        ▸
      </span>
    );
  }
  if (variant === "bracket") {
    return (
      <span
        aria-hidden="true"
        className={cn(
          "shrink-0 tabular-nums group-data-[state=rail]/sidebar:hidden",
          active ? "text-foreground" : "text-muted-foreground",
        )}
      >
        {active ? "[*]" : "[ ]"}
      </span>
    );
  }
  return null;
}

function IntentDot({ intent }: { intent: SidebarIntent }) {
  return (
    <span
      aria-hidden="true"
      data-intent={intent}
      className={cn(
        "inline-block w-1.5 h-1.5 shrink-0 mr-1 group-data-[state=rail]/sidebar:hidden",
        INTENT_DOT_CLASSES[intent],
      )}
    />
  );
}

/**
 * Renders as `<a>` by default (the spec contract — items are navigation links
 * unless explicitly action buttons). Pass `as="button"` for non-navigation
 * actions (e.g. toggles, ephemeral commands). The render-prop variant
 * `{children}` as function applies when integrating with framework Link
 * components (TanStack Router `<Link>`, Next.js `<Link>`).
 */
export function SidebarItem(props: SidebarItemProps): ReactNode {
  const generatedId = useId();
  const { variant, autoTone } = useSidebarChrome();

  const active = props.active ?? false;
  const disabled = props.disabled ?? false;
  const resolvedValue = props.value ?? generatedId;
  const resolvedIntent = autoTone ? resolveSidebarIntent(props.intent, props.value) : props.intent;

  const guardedClick = (onClick?: MouseEventHandler<HTMLElement>): MouseEventHandler<HTMLElement> =>
    (event) => {
      if (disabled) {
        event.preventDefault();
        return;
      }
      onClick?.(event);
    };

  const sharedProps = {
    className: cn(sidebarItemVariants({ variant }), props.className),
    "aria-current": active ? ("page" as const) : undefined,
    "aria-disabled": disabled || undefined,
    "data-active": active ? ("true" as const) : undefined,
    "data-intent": resolvedIntent,
    "data-diffgazer-navigation-item": "button" as const,
    "data-value": resolvedValue,
    "data-disabled": disabled ? ("" as const) : undefined,
    tabIndex: disabled ? -1 : undefined,
  };

  if (typeof props.children === "function") {
    return props.children({
      ref: props.ref as Ref<HTMLElement>,
      disabled: disabled || undefined,
      onClick: guardedClick(props.onClick as MouseEventHandler<HTMLElement> | undefined),
      ...sharedProps,
    });
  }

  const glyph = <VariantGlyph variant={variant} active={active} />;
  const dot = resolvedIntent ? <IntentDot intent={resolvedIntent} /> : null;

  if (props.as === "button") {
    const {
      active: _active,
      value: _value,
      intent: _intent,
      children,
      className: _className,
      disabled: _disabled,
      as: _as,
      ref,
      onClick,
      ...buttonProps
    } = props;
    return (
      <button
        {...buttonProps}
        ref={ref}
        type="button"
        disabled={disabled}
        {...sharedProps}
        onClick={guardedClick(onClick)}
      >
        {dot}
        {glyph}
        {children}
      </button>
    );
  }

  const {
    active: _active,
    value: _value,
    intent: _intent,
    children,
    className: _className,
    disabled: _disabled,
    as: _as,
    ref,
    onClick,
    ...anchorProps
  } = props;

  return (
    <a
      {...anchorProps}
      ref={ref}
      {...sharedProps}
      onClick={(event: ReactMouseEvent<HTMLAnchorElement>) => {
        if (disabled) {
          event.preventDefault();
          return;
        }
        onClick?.(event);
      }}
    >
      {dot}
      {glyph}
      {children}
    </a>
  );
}

